import {
    ActionRowBuilder,
    ButtonBuilder,
    ButtonStyle,
    ChannelType,
    ChatInputCommandInteraction,
    EmbedBuilder,
    MessageFlags,
    SlashCommandBuilder,
    StageChannel,
    VoiceChannel
} from "discord.js";
import {createMiltonMapLaunch} from "../../services/milton/minecraftMapActivityService";
import {handleInteractionError} from "../../utils/interactionUtils";

function asVoiceChannel(channel: VoiceChannel | StageChannel | null): VoiceChannel | StageChannel | null {
    if (!channel) {
        return null;
    }

    if (channel.type === ChannelType.GuildVoice || channel.type === ChannelType.GuildStageVoice) {
        return channel;
    }

    return null;
}

module.exports = {
    data: new SlashCommandBuilder()
        .setName("milton-map")
        .setDescription("️ Lance la carte Minecraft Milton en activite vocale")
        .addChannelOption((option) =>
            option
                .setName("salon")
                .setDescription("Salon vocal cible (sinon ton salon vocal actuel)")
                .addChannelTypes(ChannelType.GuildVoice, ChannelType.GuildStageVoice)
                .setRequired(false)
        ),

    async execute(interaction: ChatInputCommandInteraction) {
        try {
            if (!interaction.guild) {
                await interaction.reply({
                    content: "❌ Cette commande doit etre utilisee dans un serveur.",
                    flags: MessageFlags.Ephemeral
                });
                return;
            }

            const member = await interaction.guild.members.fetch(interaction.user.id);
            const selectedChannel = interaction.options.getChannel("salon", false);

            const fromOption = asVoiceChannel((selectedChannel as VoiceChannel | StageChannel | null) || null);
            const fromMemberVoice = asVoiceChannel(member.voice.channel as VoiceChannel | StageChannel | null);
            const targetVoiceChannel = fromOption || fromMemberVoice;

            if (!targetVoiceChannel) {
                await interaction.reply({
                    content: "❌ Rejoins un salon vocal (ou precise `salon`) pour lancer Milton Map.",
                    flags: MessageFlags.Ephemeral
                });
                return;
            }

            await interaction.deferReply({flags: MessageFlags.Ephemeral});

            const launch = await createMiltonMapLaunch(targetVoiceChannel);
            const buttons: ButtonBuilder[] = [
                new ButtonBuilder()
                    .setLabel("Ouvrir la map")
                    .setStyle(ButtonStyle.Link)
                    .setURL(launch.mapUrl)
            ];

            let description = `Carte Milton prete pour <#${targetVoiceChannel.id}>.`;
            if (launch.mode === "embedded") {
                buttons.unshift(
                    new ButtonBuilder()
                        .setLabel("Lancer l'activite")
                        .setStyle(ButtonStyle.Link)
                        .setURL(launch.inviteUrl)
                );
                description += "\n✅ Invite d'activite creee (mode voice activity).";
            } else {
                description += "\n⚠️ Activity Discord non configuree, lien web envoye en fallback.";
            }

            const embed = new EmbedBuilder()
                .setColor(0x57f287)
                .setTitle(" Milton Map Viewer")
                .setDescription(description)
                .setFooter({text: "Astuce: configure MILTON_ACTIVITY_APPLICATION_ID pour un vrai lancement type Wordle/Watch Together."});

            const row = new ActionRowBuilder<ButtonBuilder>().addComponents(...buttons);
            await interaction.editReply({
                embeds: [embed],
                components: [row]
            });
        } catch (error: any) {
            await handleInteractionError(interaction, error, "MiltonMap");
        }
    }
};

import path from "path";
import {REST, Routes} from "discord.js";
import {createLogger} from "../utils/logger";

const logger = createLogger("DeployCommands");

// Liste des commandes qui doivent être UNIQUEMENT dans le serveur (pas exportées en externe)
const GUILD_ONLY_COMMANDS = [
    "reset",
    "reset-counter",
    "add-note",
    "set-birthday",
    "remove-birthday",
    "remove-note",
    "set-status",
    "stop-event",
    "test-event",
    "auto-lowpower",
    "blacklist",
    "blacklist-game",
    "whitelist-game",
    "lowpower",
    "leaderboard",
    "test-mission",
    "test-rewind",
    "standby-status",
    "findmeme",
    "answer",
    "harvest",
    "Déplacer le message", // Commande de menu contextuel
    "configure-free-games" // Commande d'administration pour configurer les jeux gratuits (ex: ajouter un nouveau store)
];

const globalCommands: any[] = [];
const guildOnlyCommands: any[] = [];
const foldersPath = path.join(__dirname, "..", "commands");
const commandFolders = require("fs").readdirSync(foldersPath);

for (const folder of commandFolders) {
    const commandsPath = path.join(foldersPath, folder);
    const commandFiles = require("fs")
        .readdirSync(commandsPath)
        .filter((file: string) => file.endsWith(".js"));

    for (const file of commandFiles) {
        const filePath = path.join(commandsPath, file);
        const command = require(filePath);
        if ("data" in command && "execute" in command) {
            const commandData = command.data.toJSON();

            // Vérifier si c'est une commande guild-only
            if (GUILD_ONLY_COMMANDS.includes(commandData.name)) {
                guildOnlyCommands.push(commandData);
            } else {
                globalCommands.push(commandData);
            }
        } else {
            logger.warn(`The command at ${filePath} is missing a required "data" or "execute" property.`);
        }
    }
}

const deployCommands = async () => {
    const rest = new REST().setToken(process.env.DISCORD_LLM_BOT_TOKEN!);
    const GUILD_ID = process.env.GUILD_ID!;

    try {
        logger.info(`Started refreshing application (/) commands.`);
        logger.info(`- ${globalCommands.length} global commands (with User App support)`);
        logger.info(`- ${guildOnlyCommands.length} guild-only commands (admin/owner)`);

        // Déployer les commandes globales avec User App support
        const globalCommandsWithUserApp = globalCommands.map(cmd => ({
            ...cmd,
            // 0 = Guild Install (serveur), 1 = User Install (application utilisateur)
            integration_types: [0, 1],
            // 0 = Guild (serveur), 1 = Bot DM, 2 = Group DM
            contexts: [0, 1, 2]
        }));

        const globalData: any = await rest.put(
            Routes.applicationCommands(process.env.DISCORD_LLM_BOT_CLIENT_ID!),
            {body: globalCommandsWithUserApp}
        );

        logger.info(`✅ Successfully deployed ${globalData.length} global commands with User App support.`);

        // Déployer les commandes guild-only (uniquement dans le serveur, pas de User Apps)
        const guildData: any = await rest.put(
            Routes.applicationGuildCommands(process.env.DISCORD_LLM_BOT_CLIENT_ID!, GUILD_ID),
            {body: guildOnlyCommands}
        );

        logger.info(`✅ Successfully deployed ${guildData.length} guild-only commands (admin/owner).`);

    } catch (error) {
        logger.error("Error deploying commands:", error);
    }
};
export default deployCommands;

